(() => {
  'use strict';

  if (window.__pcbw_ff12_init) return;
  window.__pcbw_ff12_init = true;

  const CONFIG = {
    namespace: '__pcbw_ff12',
    storageKey: '__pcbw_ff12_state',
    schemaVersion: 2,
    maxEventHistory: 420,
    maxNotifications: 140,
    maxSnapshots: 10,
    maxContextMessages: 6,
    travelHours: 6,
    campHours: 8,
    uiScreens: ['dashboard', 'map', 'party', 'inventory', 'contracts', 'timeline', 'codex', 'factions', 'settings', 'debug'],
    world: {
      regionCount: 9,
      biomes: ['storm-fens', 'ash-steppe', 'glasswood', 'ember-ridge', 'salt-basin', 'iron-marsh', 'windscar-canyon'],
      weather: ['clear', 'fog', 'acid-drizzle', 'dust-storm', 'cold-front', 'electric-wind', 'heatwave'],
      landmarks: ['collapsed relay', 'sunken observatory', 'fracture-gate', 'hydroforge ruins', 'warding spire', 'buried station']
    },
    resources: {
      caps: { food: 220, water: 220, medicine: 60, salvage: 180, fuel: 120, relic: 40 }
    }
  };

  const Utils = {
    nowIso() {
      return new Date().toISOString();
    },
    clone(value, fallback = null) {
      try {
        return JSON.parse(JSON.stringify(value));
      } catch (_err) {
        return fallback;
      }
    },
    clamp(v, min, max) {
      return Math.max(min, Math.min(max, v));
    },
    hash(input) {
      const text = String(input || '');
      let h = 2166136261;
      for (let i = 0; i < text.length; i++) {
        h ^= text.charCodeAt(i);
        h = Math.imul(h, 16777619);
      }
      return h >>> 0;
    },
    rng(seed) {
      let a = Utils.hash(seed);
      return function rand() {
        a += 0x6D2B79F5;
        let t = a;
        t = Math.imul(t ^ (t >>> 15), t | 1);
        t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
      };
    },
    pick(rand, list) {
      if (!Array.isArray(list) || !list.length) return null;
      return list[Math.floor(rand() * list.length) % list.length];
    },
    esc(value) {
      return String(value == null ? '' : value)
        .replaceAll('&', '&amp;')
        .replaceAll('<', '&lt;')
        .replaceAll('>', '&gt;')
        .replaceAll('"', '&quot;')
        .replaceAll("'", '&#39;');
    },
    ensureStores() {
      oc.character.customData ||= {};
      oc.character.customData.PUBLIC ||= {};
      oc.thread.customData ||= {};
    }
  };

  const WorldGen = {
    createSeed(seedHint) {
      if (seedHint && String(seedHint).trim()) return String(seedHint).trim().toLowerCase();
      const base = [Date.now(), oc.character?.name || 'frontier-foundry-1-2', oc.thread?.messages?.length || 0].join('|');
      return 'ff12-' + Utils.hash(base).toString(36);
    },
    createRegions(seed) {
      const rand = Utils.rng(seed + '|regions');
      const regions = [];
      for (let i = 0; i < CONFIG.world.regionCount; i++) {
        const id = 'rg-' + (i + 1);
        const biome = Utils.pick(rand, CONFIG.world.biomes);
        const danger = Utils.clamp(Math.floor(rand() * 5) + 1, 1, 5);
        const resources = [
          Utils.pick(rand, ['food', 'water', 'medicine', 'salvage']),
          Utils.pick(rand, ['food', 'water', 'salvage', 'fuel', 'relic'])
        ].filter((v, idx, arr) => arr.indexOf(v) === idx);
        regions.push({
          id,
          name: 'Region ' + (i + 1),
          biome,
          danger,
          landmarks: [Utils.pick(rand, CONFIG.world.landmarks), Utils.pick(rand, CONFIG.world.landmarks)]
            .filter((v, idx, arr) => arr.indexOf(v) === idx),
          resources,
          neighbors: []
        });
      }
      for (let i = 0; i < regions.length; i++) {
        const a = (i + 1) % regions.length;
        const b = (i + 2) % regions.length;
        const c = (i - 1 + regions.length) % regions.length;
        regions[i].neighbors = [regions[a].id, regions[b].id, regions[c].id].filter((v, idx, arr) => arr.indexOf(v) === idx);
      }
      return regions;
    },
    createWorld(seed) {
      const rand = Utils.rng(seed + '|world');
      const regions = WorldGen.createRegions(seed);
      return {
        seed,
        regions,
        currentRegionId: regions[0].id,
        discoveredRegionIds: [regions[0].id],
        routeHistory: [regions[0].id],
        weather: {
          current: Utils.pick(rand, CONFIG.world.weather),
          severity: Utils.clamp(Math.floor(rand() * 3) + 1, 1, 5),
          pressure: 'stable'
        },
        environment: {
          visibility: 'clear',
          hazard: 2,
          anomalyDrift: 12
        }
      };
    }
  };

  const Models = {
    party(seed) {
      const rand = Utils.rng(seed + '|party');
      const names = ['Mara Quell', 'Torin Ash', 'Sera Vale', 'Iven Drax', 'Nyra Holt', 'Kade Mercer'];
      const roles = ['Pathfinder', 'Quartermaster', 'Medic', 'Engineer', 'Scout', 'Negotiator'];
      const roster = Array.from({ length: 5 }).map((_, i) => ({
        id: 'pm-' + (i + 1),
        name: names[i],
        role: roles[i],
        morale: Utils.clamp(58 + Math.floor(rand() * 30), 0, 100),
        fatigue: Utils.clamp(10 + Math.floor(rand() * 22), 0, 100),
        condition: 'steady',
        traits: [Utils.pick(rand, ['disciplined', 'calculating', 'resilient', 'stoic', 'restless'])]
      }));
      return {
        roster,
        reserves: [],
        moraleAverage: 0,
        fatigueAverage: 0
      };
    },
    resources() {
      return {
        stock: { food: 130, water: 136, medicine: 26, salvage: 48, fuel: 26, relic: 1 },
        caps: Utils.clone(CONFIG.resources.caps, {}),
        rates: { foodPerTravelTurn: 4, waterPerTravelTurn: 4, foodPerCampTurn: 2, waterPerCampTurn: 2 }
      };
    },
    factions(seed) {
      const rand = Utils.rng(seed + '|factions');
      const source = [
        ['river-compact', 'River Compact', 'trade leverage'],
        ['embersynod', 'Ember Synod', 'knowledge custody'],
        ['ironwardens', 'Iron Wardens', 'security control'],
        ['verdant-covenant', 'Verdant Covenant', 'ecology restoration']
      ];
      const out = {};
      for (const [id, name, doctrine] of source) {
        out[id] = {
          id,
          name,
          doctrine,
          reputation: Utils.clamp(Math.floor(rand() * 36) - 12, -100, 100),
          tension: Utils.clamp(Math.floor(rand() * 65), 0, 100),
          notes: []
        };
      }
      return out;
    },
    contracts(seed, world) {
      const rand = Utils.rng(seed + '|contracts');
      const pickRegion = (idx) => world.regions[idx] ? world.regions[idx].id : world.currentRegionId;
      const mk = (id, title, faction, type, regionId, deadline) => ({
        id,
        title,
        issuerFactionId: faction,
        type,
        regionId,
        deadlineDay: deadline,
        progress: 0,
        status: 'available',
        risk: Utils.clamp(Math.floor(rand() * 5) + 1, 1, 5),
        objectives: [
          { id: id + '-o1', text: 'Reach target theater node', done: false },
          { id: id + '-o2', text: 'Resolve local pressure condition', done: false },
          { id: id + '-o3', text: 'Secure objective and report', done: false }
        ],
        rewards: { resources: { salvage: 16, medicine: 5 }, reputation: { [faction]: 8 } },
        consequences: { morale: -4, reputation: { [faction]: -10 } }
      });
      const c1 = mk('ct-1', 'Relay Stabilization', 'river-compact', 'recovery', pickRegion(2), 7);
      c1.status = 'active';
      c1.progress = 1;
      c1.objectives[0].done = true;
      const c2 = mk('ct-2', 'Archive Sweep', 'embersynod', 'intel', pickRegion(4), 9);
      const c3 = mk('ct-3', 'Supply Corridor Arbitration', 'ironwardens', 'diplomacy', pickRegion(6), 11);
      return { active: [c1], backlog: [c2, c3], completed: [], failed: [] };
    },
    codex() {
      return {
        entries: [
          { id: 'frontier-charter', title: 'Frontier Charter', body: 'Expedition authority is provisional and tied to delivered outcomes.', unlockedAt: Utils.nowIso() },
          { id: 'foundry-protocol', title: 'Foundry Protocol', body: 'Operational continuity outranks narrative ornament.', unlockedAt: Utils.nowIso() }
        ],
        discoveries: []
      };
    }
  };

  const State = {
    defaults(seedHint) {
      const seed = WorldGen.createSeed(seedHint);
      const world = WorldGen.createWorld(seed);
      const party = Models.party(seed);
      return {
        schemaVersion: CONFIG.schemaVersion,
        expedition: {
          id: 'exp-' + Date.now(),
          name: 'Chronicle Foundry Expedition',
          status: 'active',
          seed,
          startedAt: Utils.nowIso(),
          notes: ''
        },
        time: { day: 1, hour: 7, turn: 0, phase: 'dawn', totalHours: 0 },
        world,
        resources: Models.resources(),
        party,
        factions: Models.factions(seed),
        contracts: Models.contracts(seed, world),
        codex: Models.codex(),
        scene: { mode: 'onboarding', summary: 'Foundation systems calibrated.', urgency: 'low', tags: ['boot', 'expedition'] },
        events: { history: [], counters: { travel: 0, camp: 0, command: 0, uiAction: 0 } },
        notifications: [],
        snapshots: [],
        ui: {
          visible: false,
          screen: 'dashboard',
          tutorialComplete: false,
          tutorialStep: 0,
          settings: { compact: false, eventDensity: 1 }
        },
        system: { lastSavedAt: Utils.nowIso(), lastLoadedAt: Utils.nowIso(), contextKeys: [] }
      };
    }
  };

  const Migrations = {
    apply(raw) {
      if (!raw || typeof raw !== 'object') return null;
      const s = raw;
      s.schemaVersion ||= 0;
      if (s.schemaVersion < 1) {
        s.notifications ||= [];
        s.snapshots ||= [];
        s.system ||= { lastSavedAt: Utils.nowIso(), lastLoadedAt: Utils.nowIso(), contextKeys: [] };
        s.schemaVersion = 1;
      }
      if (s.schemaVersion < 2) {
        s.ui ||= { visible: false, screen: 'dashboard', tutorialComplete: false, tutorialStep: 0, settings: { compact: false, eventDensity: 1 } };
        s.codex ||= { entries: [], discoveries: [] };
        s.scene ||= { mode: 'operations', summary: 'Phase transition', urgency: 'medium', tags: ['migrated'] };
        s.schemaVersion = 2;
      }
      s.schemaVersion = CONFIG.schemaVersion;
      return s;
    }
  };

  const Engine = {
    state: null,
    validateShape(s) {
      return !!(
        s && typeof s === 'object' &&
        s.world && Array.isArray(s.world.regions) &&
        s.resources && s.resources.stock && s.resources.caps &&
        s.party && Array.isArray(s.party.roster) &&
        s.contracts && Array.isArray(s.contracts.active) &&
        s.factions && typeof s.factions === 'object' &&
        s.events && Array.isArray(s.events.history) &&
        s.ui && typeof s.ui === 'object'
      );
    },
    readState() {
      Utils.ensureStores();
      const ns = CONFIG.namespace;
      const key = CONFIG.storageKey;
      const candidates = [oc.thread.customData[ns], oc.character.customData[ns], oc.character.customData.PUBLIC[key]];
      for (const c of candidates) {
        if (!c) continue;
        const clone = Utils.clone(c, null);
        if (!clone) continue;
        const migrated = Migrations.apply(clone);
        if (!Engine.validateShape(migrated)) continue;
        migrated.system.lastLoadedAt = Utils.nowIso();
        return migrated;
      }
      return State.defaults();
    },
    writeState() {
      Utils.ensureStores();
      const serial = Utils.clone(Engine.state, null);
      if (!serial) return;
      serial.system.lastSavedAt = Utils.nowIso();
      oc.thread.customData[CONFIG.namespace] = serial;
      oc.character.customData[CONFIG.namespace] = serial;
      oc.character.customData.PUBLIC[CONFIG.storageKey] = serial;
      Engine.state = serial;
    },
    currentRegion() {
      return Engine.state.world.regions.find((r) => r.id === Engine.state.world.currentRegionId) || null;
    },
    recomputePartyAverages() {
      const roster = Engine.state.party.roster;
      if (!roster.length) {
        Engine.state.party.moraleAverage = 0;
        Engine.state.party.fatigueAverage = 0;
        return;
      }
      Engine.state.party.moraleAverage = Math.round(roster.reduce((a, m) => a + m.morale, 0) / roster.length);
      Engine.state.party.fatigueAverage = Math.round(roster.reduce((a, m) => a + m.fatigue, 0) / roster.length);
    },
    bootstrap() {
      Engine.state = Engine.readState();
      Engine.recomputePartyAverages();
      if (!Engine.state.events.history.length) {
        Systems.events.log('system', 'Phase 2 engine boot complete with UI and weighted event baseline.');
      }
      Systems.ui.applyShortcuts();
      Systems.context.syncReminder();
      Systems.ui.bindGlobalActions();
      if (Engine.state.ui.visible) {
        Systems.ui.open(false);
      } else {
        try { oc.window.hide(); } catch (_err) {}
      }
      Engine.writeState();
    }
  };

  const Systems = {
    notifications: {
      push(type, text) {
        const row = { id: 'ntf-' + Date.now() + '-' + Math.floor(Math.random() * 10000), at: Utils.nowIso(), type, text: String(text || '').slice(0, 280) };
        Engine.state.notifications.push(row);
        Engine.state.notifications = Engine.state.notifications.slice(-CONFIG.maxNotifications);
      }
    },
    events: {
      log(type, detail) {
        const row = { id: 'ev-' + Date.now() + '-' + Math.floor(Math.random() * 100000), at: Utils.nowIso(), turn: Engine.state.time.turn, type, detail: String(detail || '').slice(0, 700) };
        Engine.state.events.history.push(row);
        Engine.state.events.history = Engine.state.events.history.slice(-CONFIG.maxEventHistory);
        return row;
      },
      summarize(limit = 5) {
        const rows = Engine.state.events.history.slice(-limit);
        if (!rows.length) return 'No notable events logged.';
        return rows.map((r) => '- T' + r.turn + ' [' + r.type + '] ' + r.detail).join('\n');
      },
      resolveWeighted(source) {
        const s = Engine.state;
        const region = Engine.currentRegion();
        const lowFood = s.resources.stock.food < 40;
        const lowWater = s.resources.stock.water < 40;
        const highFatigue = s.party.fatigueAverage > 70;
        const severeWeather = s.world.weather.severity >= 4;

        const weights = [
          ['discovery', 9 + (region ? region.danger : 2)],
          ['hostile-contact', 8 + (region ? region.danger : 2) + (highFatigue ? 2 : 0)],
          ['faction-friction', 7 + (severeWeather ? 1 : 0)],
          ['resource-windfall', 6 + (lowFood || lowWater ? 4 : 0)],
          ['weather-front', 8 + (severeWeather ? 3 : 0)],
          ['crew-strain', 7 + (highFatigue ? 5 : 0)],
          ['contract-lead', 6 + (s.contracts.active.length ? 3 : 1)]
        ];

        const density = Utils.clamp(Number(s.ui.settings.eventDensity || 1), 0.5, 2);
        for (const w of weights) w[1] = Math.max(1, Math.round(w[1] * density));

        const total = weights.reduce((a, w) => a + w[1], 0);
        const rand = Utils.rng(s.expedition.seed + '|event|' + s.time.turn + '|' + source)();
        let pick = Math.floor(rand * total);
        let chosen = weights[0][0];
        for (const [key, w] of weights) {
          pick -= w;
          if (pick < 0) { chosen = key; break; }
        }

        const effects = {
          sceneMode: 'operations',
          summary: '',
          urgency: 'medium'
        };

        if (chosen === 'discovery') {
          s.resources.stock.salvage = Utils.clamp(s.resources.stock.salvage + 6, 0, s.resources.caps.salvage);
          s.codex.discoveries.push({ id: 'disc-' + Date.now(), at: Utils.nowIso(), text: 'Recovered frontier data from ' + (region ? region.name : s.world.currentRegionId) + '.' });
          effects.summary = 'Discovery operation yielded salvage and codex leads.';
          effects.urgency = 'low';
        } else if (chosen === 'hostile-contact') {
          for (const m of s.party.roster) {
            m.morale = Utils.clamp(m.morale - 4, 0, 100);
            m.fatigue = Utils.clamp(m.fatigue + 6, 0, 100);
          }
          s.resources.stock.medicine = Utils.clamp(s.resources.stock.medicine - 1, 0, s.resources.caps.medicine);
          effects.summary = 'Hostile contact increased fatigue and reduced morale.';
          effects.urgency = 'high';
        } else if (chosen === 'faction-friction') {
          const entries = Object.values(s.factions);
          const target = entries[Math.floor(Utils.rng(s.expedition.seed + '|faction|' + s.time.turn)() * entries.length)] || entries[0];
          if (target) {
            target.reputation = Utils.clamp(target.reputation - 4, -100, 100);
            target.tension = Utils.clamp(target.tension + 6, 0, 100);
            target.notes.push('Operational disagreement registered on day ' + s.time.day + '.');
            target.notes = target.notes.slice(-8);
            effects.summary = target.name + ' escalated pressure after frontier maneuver.';
          } else {
            effects.summary = 'Faction pressure rose without clear diplomatic channel.';
          }
          effects.urgency = 'medium';
        } else if (chosen === 'resource-windfall') {
          s.resources.stock.food = Utils.clamp(s.resources.stock.food + 10, 0, s.resources.caps.food);
          s.resources.stock.water = Utils.clamp(s.resources.stock.water + 12, 0, s.resources.caps.water);
          effects.summary = 'Scavenging run improved food and water reserves.';
          effects.urgency = 'low';
        } else if (chosen === 'weather-front') {
          s.world.weather.severity = Utils.clamp(s.world.weather.severity + 1, 1, 5);
          s.world.environment.hazard = Utils.clamp(s.world.environment.hazard + 1, 1, 5);
          effects.summary = 'Weather front intensified environmental hazard.';
          effects.urgency = 'high';
        } else if (chosen === 'crew-strain') {
          for (const m of s.party.roster) {
            m.morale = Utils.clamp(m.morale - 3, 0, 100);
          }
          effects.summary = 'Crew strain affected cohesion and morale.';
          effects.urgency = 'medium';
        } else if (chosen === 'contract-lead') {
          const active = s.contracts.active[0];
          if (active) {
            active.progress = Utils.clamp(active.progress + 1, 0, active.objectives.length);
            if (active.objectives[active.progress - 1]) active.objectives[active.progress - 1].done = true;
            if (active.progress >= active.objectives.length) {
              active.status = 'completed';
              s.contracts.completed.push(active);
              s.contracts.active.shift();
              const rep = active.rewards.reputation || {};
              Object.keys(rep).forEach((f) => {
                if (s.factions[f]) s.factions[f].reputation = Utils.clamp(s.factions[f].reputation + rep[f], -100, 100);
              });
              const rs = active.rewards.resources || {};
              Object.keys(rs).forEach((r) => {
                if (typeof s.resources.stock[r] === 'number') s.resources.stock[r] = Utils.clamp(s.resources.stock[r] + rs[r], 0, s.resources.caps[r]);
              });
              effects.summary = 'Active contract completed with material and diplomatic gains.';
              effects.urgency = 'low';
            } else {
              effects.summary = 'Contract lead advanced objective progress.';
              effects.urgency = 'medium';
            }
          } else {
            effects.summary = 'No active contract to advance; lead archived.';
            effects.urgency = 'low';
          }
        }

        Engine.recomputePartyAverages();
        s.scene.mode = effects.sceneMode;
        s.scene.summary = effects.summary;
        s.scene.urgency = effects.urgency;
        s.scene.tags = [chosen, source, s.world.currentRegionId];

        const log = Systems.events.log('event', '[' + chosen + '] ' + effects.summary);
        Systems.notifications.push('event', effects.summary);
        return log;
      }
    },
    simulation: {
      advanceTime(hours) {
        const s = Engine.state;
        s.time.totalHours += hours;
        s.time.hour += hours;
        while (s.time.hour >= 24) {
          s.time.hour -= 24;
          s.time.day += 1;
        }
        s.time.turn += 1;
        if (s.time.hour < 5) s.time.phase = 'deep-night';
        else if (s.time.hour < 8) s.time.phase = 'dawn';
        else if (s.time.hour < 12) s.time.phase = 'morning';
        else if (s.time.hour < 17) s.time.phase = 'afternoon';
        else if (s.time.hour < 20) s.time.phase = 'dusk';
        else s.time.phase = 'night';
      },
      shiftWeather() {
        const s = Engine.state;
        const rand = Utils.rng(s.expedition.seed + '|weather|' + s.time.turn);
        s.world.weather.current = Utils.pick(rand, CONFIG.world.weather);
        s.world.weather.severity = Utils.clamp(Math.floor(rand() * 5) + 1, 1, 5);
        s.world.weather.pressure = s.world.weather.severity >= 4 ? 'volatile' : s.world.weather.severity >= 3 ? 'unsettled' : 'stable';
        s.world.environment.visibility = s.world.weather.severity >= 4 ? 'poor' : s.world.weather.severity >= 3 ? 'mixed' : 'clear';
        s.world.environment.hazard = Utils.clamp((Engine.currentRegion()?.danger || 2) + Math.floor((s.world.weather.severity - 2) / 2), 1, 5);
      },
      applySupplyPressure(mode) {
        const s = Engine.state;
        const foodRate = mode === 'camp' ? s.resources.rates.foodPerCampTurn : s.resources.rates.foodPerTravelTurn;
        const waterRate = mode === 'camp' ? s.resources.rates.waterPerCampTurn : s.resources.rates.waterPerTravelTurn;
        s.resources.stock.food = Utils.clamp(s.resources.stock.food - foodRate, 0, s.resources.caps.food);
        s.resources.stock.water = Utils.clamp(s.resources.stock.water - waterRate, 0, s.resources.caps.water);
        if (s.resources.stock.food === 0 || s.resources.stock.water === 0) {
          for (const m of s.party.roster) {
            m.morale = Utils.clamp(m.morale - 5, 0, 100);
            m.fatigue = Utils.clamp(m.fatigue + 5, 0, 100);
          }
          Systems.notifications.push('warning', 'Critical supply depletion is degrading party condition.');
          Systems.events.log('pressure', 'Critical food/water depletion imposed morale and fatigue penalties.');
        }
      },
      applyFatigue(mode) {
        const s = Engine.state;
        for (const m of s.party.roster) {
          if (mode === 'camp') {
            m.fatigue = Utils.clamp(m.fatigue - 9, 0, 100);
            m.morale = Utils.clamp(m.morale + 2, 0, 100);
          } else {
            m.fatigue = Utils.clamp(m.fatigue + 8, 0, 100);
            if (m.fatigue > 80) m.condition = 'strained';
            if (m.fatigue > 92) m.condition = 'critical';
            if (m.fatigue < 70) m.condition = 'steady';
          }
        }
        Engine.recomputePartyAverages();
      }
    },
    actions: {
      travel(targetRegionId) {
        const s = Engine.state;
        const from = Engine.currentRegion();
        if (!targetRegionId) {
          Systems.notifications.push('error', 'Travel failed: choose a target region.');
          return false;
        }
        if (!from || !from.neighbors.includes(targetRegionId)) {
          Systems.notifications.push('error', 'Travel failed: target is not adjacent to current region.');
          return false;
        }
        s.world.currentRegionId = targetRegionId;
        if (!s.world.discoveredRegionIds.includes(targetRegionId)) s.world.discoveredRegionIds.push(targetRegionId);
        s.world.routeHistory.push(targetRegionId);
        Systems.simulation.advanceTime(CONFIG.travelHours);
        Systems.simulation.shiftWeather();
        Systems.simulation.applySupplyPressure('travel');
        Systems.simulation.applyFatigue('travel');
        Systems.events.resolveWeighted('travel');
        s.events.counters.travel += 1;
        Systems.events.log('travel', 'Moved from ' + (from ? from.id : 'unknown') + ' to ' + targetRegionId + '.');
        Systems.notifications.push('info', 'Travel complete: now in ' + targetRegionId + '.');
        return true;
      },
      camp() {
        const s = Engine.state;
        Systems.simulation.advanceTime(CONFIG.campHours);
        Systems.simulation.shiftWeather();
        Systems.simulation.applySupplyPressure('camp');
        Systems.simulation.applyFatigue('camp');
        Systems.events.resolveWeighted('camp');
        s.events.counters.camp += 1;
        Systems.events.log('camp', 'Camp cycle completed with recovery and event resolution.');
        Systems.notifications.push('info', 'Camp completed. Fatigue adjusted and events resolved.');
        return true;
      },
      acceptContract(contractId) {
        const s = Engine.state;
        const idx = s.contracts.backlog.findIndex((c) => c.id === contractId);
        if (idx < 0) {
          Systems.notifications.push('error', 'Contract accept failed: contract not found.');
          return false;
        }
        const c = s.contracts.backlog.splice(idx, 1)[0];
        c.status = 'active';
        s.contracts.active.push(c);
        Systems.events.log('contract', 'Accepted contract ' + c.title + '.');
        Systems.notifications.push('info', 'Contract accepted: ' + c.title + '.');
        return true;
      },
      saveSnapshot(label = 'manual') {
        const s = Engine.state;
        const snap = {
          id: 'snap-' + Date.now(),
          at: Utils.nowIso(),
          label,
          state: Utils.clone({ ...s, snapshots: [], notifications: s.notifications.slice(-30) }, null)
        };
        if (!snap.state) {
          Systems.notifications.push('error', 'Snapshot failed: serialization error.');
          return false;
        }
        s.snapshots.push(snap);
        s.snapshots = s.snapshots.slice(-CONFIG.maxSnapshots);
        Systems.events.log('snapshot', 'Saved snapshot ' + snap.id + ' (' + label + ').');
        Systems.notifications.push('info', 'Snapshot saved: ' + snap.id + '.');
        return true;
      },
      restoreSnapshot(snapshotId) {
        const s = Engine.state;
        const found = s.snapshots.find((x) => x.id === snapshotId);
        if (!found || !found.state) {
          Systems.notifications.push('error', 'Restore failed: snapshot not found.');
          return false;
        }
        const keepSnapshots = s.snapshots;
        const restored = Utils.clone(found.state, null);
        if (!restored || !Engine.validateShape(restored)) {
          Systems.notifications.push('error', 'Restore failed: snapshot payload invalid.');
          return false;
        }
        restored.snapshots = keepSnapshots;
        restored.notifications = (restored.notifications || []).slice(-CONFIG.maxNotifications);
        restored.system = restored.system || {};
        restored.system.lastLoadedAt = Utils.nowIso();
        Engine.state = restored;
        Systems.events.log('snapshot', 'Restored snapshot ' + snapshotId + '.');
        Systems.notifications.push('warning', 'Snapshot restored: ' + snapshotId + '.');
        return true;
      },
      newExpedition(seedHint) {
        Engine.state = State.defaults(seedHint);
        Systems.events.log('system', 'New expedition initialized: ' + Engine.state.expedition.seed + '.');
        Systems.notifications.push('info', 'New expedition initialized. Seed: ' + Engine.state.expedition.seed + '.');
      },
      resetCurrentSeed() {
        const seed = Engine.state.expedition.seed;
        Systems.actions.newExpedition(seed);
        Systems.events.log('system', 'Safety reset complete on seed ' + seed + '.');
      }
    },
    context: {
      build() {
        const s = Engine.state;
        const region = Engine.currentRegion();
        const topFaction = Object.values(s.factions).sort((a, b) => b.reputation - a.reputation)[0];
        return [
          'ExpeditionContext v' + s.schemaVersion,
          'Seed: ' + s.expedition.seed,
          'Time: day ' + s.time.day + ', hour ' + s.time.hour + ', turn ' + s.time.turn,
          'Region: ' + (region ? region.name + ' [' + region.id + ']' : s.world.currentRegionId),
          'Weather: ' + s.world.weather.current + ' sev ' + s.world.weather.severity + ', pressure ' + s.world.weather.pressure,
          'Resources: food ' + s.resources.stock.food + ', water ' + s.resources.stock.water + ', med ' + s.resources.stock.medicine + ', salvage ' + s.resources.stock.salvage + ', fuel ' + s.resources.stock.fuel,
          'Party avg morale/fatigue: ' + s.party.moraleAverage + '/' + s.party.fatigueAverage,
          'Active contracts: ' + s.contracts.active.length + ', backlog: ' + s.contracts.backlog.length,
          'Top faction: ' + (topFaction ? topFaction.name + ' rep ' + topFaction.reputation + ' tension ' + topFaction.tension : 'none'),
          'Scene: ' + s.scene.summary,
          'Recent events:\n' + Systems.events.summarize(4)
        ].join('\n');
      },
      injectHidden() {
        const key = 'ctx-' + Date.now();
        oc.thread.messages.push({
          author: 'system',
          content: Systems.context.build(),
          hiddenFrom: ['user'],
          expectsReply: false,
          customData: { __pcbw_ff12_context: true, key }
        });
        Engine.state.system.contextKeys.push(key);
        Engine.state.system.contextKeys = Engine.state.system.contextKeys.slice(-CONFIG.maxContextMessages);
        Systems.context.pruneOld();
      },
      pruneOld() {
        const indexes = [];
        for (let i = 0; i < oc.thread.messages.length; i++) {
          const m = oc.thread.messages[i];
          if (m?.author === 'system' && m?.customData?.__pcbw_ff12_context) indexes.push(i);
        }
        const over = Math.max(0, indexes.length - CONFIG.maxContextMessages);
        for (let i = 0; i < over; i++) {
          oc.thread.messages.splice(indexes[i] - i, 1);
        }
      },
      syncReminder() {
        const s = Engine.state;
        const region = Engine.currentRegion();
        oc.character.reminderMessage = [
          'State-locked expedition engine active.',
          'Seed ' + s.expedition.seed + '. Day ' + s.time.day + ', hour ' + s.time.hour + ', turn ' + s.time.turn + '.',
          'Region ' + (region ? region.id + ' ' + region.biome : s.world.currentRegionId) + '.',
          'Track resources, fatigue pressure, faction standing, contract deadlines, and event consequences.',
          'Always output SITREP, progression, constraints, then action options.'
        ].join(' ');
      }
    },
    ui: {
      applyShortcuts() {
        oc.thread.shortcutButtons = [
          { name: 'Open Ops UI', message: '!ui', insertionType: 'replace', autoSend: true, clearAfterSend: true },
          { name: 'Status', message: '!status', insertionType: 'replace', autoSend: true, clearAfterSend: true },
          { name: 'Travel', message: '!travel rg-2', insertionType: 'replace', autoSend: true, clearAfterSend: true },
          { name: 'Camp', message: '!camp', insertionType: 'replace', autoSend: true, clearAfterSend: true },
          { name: 'Snapshot', message: '!snapshot', insertionType: 'replace', autoSend: true, clearAfterSend: true }
        ];
