      bindGlobalActions() {
        window.__pcbw_ff12_ui_action = (action, payload) => {
          Systems.ui.dispatch(String(action || ''), payload || {});
        };
      },
      open(showToast = true) {
        Engine.state.ui.visible = true;
        try { oc.window.show(); } catch (_err) {}
        Systems.ui.render();
        if (showToast) Systems.notifications.push('info', 'Operations UI opened.');
      },
      close(showToast = true) {
        Engine.state.ui.visible = false;
        try { oc.window.hide(); } catch (_err) {}
        if (showToast) Systems.notifications.push('info', 'Operations UI closed.');
      },
      dispatch(action, payload) {
        Engine.state.events.counters.uiAction += 1;
        let needsRender = true;
        if (action === 'nav') {
          if (CONFIG.uiScreens.includes(payload.screen)) Engine.state.ui.screen = payload.screen;
        } else if (action === 'travel') {
          Systems.actions.travel(payload.regionId);
          Engine.state.ui.screen = 'map';
        } else if (action === 'camp') {
          Systems.actions.camp();
          Engine.state.ui.screen = 'dashboard';
        } else if (action === 'accept-contract') {
          Systems.actions.acceptContract(payload.contractId);
          Engine.state.ui.screen = 'contracts';
        } else if (action === 'dismiss-tutorial') {
          Engine.state.ui.tutorialComplete = true;
          Systems.notifications.push('info', 'Onboarding dismissed.');
        } else if (action === 'toggle-compact') {
          Engine.state.ui.settings.compact = !Engine.state.ui.settings.compact;
          Systems.notifications.push('info', 'Compact mode ' + (Engine.state.ui.settings.compact ? 'enabled' : 'disabled') + '.');
        } else if (action === 'set-event-density') {
          const val = Number(payload.value);
          if (!Number.isNaN(val)) {
            Engine.state.ui.settings.eventDensity = Utils.clamp(val, 0.5, 2);
            Systems.notifications.push('info', 'Event density set to ' + Engine.state.ui.settings.eventDensity + '.');
          }
        } else if (action === 'save-snapshot') {
          Systems.actions.saveSnapshot('ui');
        } else if (action === 'restore-snapshot') {
          Systems.actions.restoreSnapshot(payload.snapshotId);
        } else if (action === 'clear-notifications') {
          Engine.state.notifications = [];
        } else if (action === 'close-ui') {
          Systems.ui.close(false);
          needsRender = false;
        } else if (action === 'open-ui') {
          Systems.ui.open(false);
        } else {
          needsRender = false;
        }

        Systems.context.syncReminder();
        Engine.writeState();
        if (needsRender && Engine.state.ui.visible) Systems.ui.render();
      },
      render() {
        const s = Engine.state;
        const region = Engine.currentRegion();
        const nav = CONFIG.uiScreens.map((screen) => {
          const active = s.ui.screen === screen ? ' active' : '';
          return '<button class="pcbw-nav-btn' + active + '" data-act="nav" data-screen="' + screen + '">' + Utils.esc(screen) + '</button>';
        }).join('');

        const toasts = s.notifications.slice(-3).map((n) => '<div class="pcbw-toast ' + Utils.esc(n.type) + '">' + Utils.esc(n.text) + '</div>').join('');

        document.body.innerHTML = '<style>' + Systems.ui.styles() + '</style>' +
          '<div class="pcbw-app ' + (s.ui.settings.compact ? 'compact' : '') + '">' +
          '<header class="pcbw-header"><div><strong>Chronicle Foundry Ops</strong><div class="pcbw-sub">Seed ' + Utils.esc(s.expedition.seed) + ' · Day ' + s.time.day + ' · Hour ' + s.time.hour + ' · Turn ' + s.time.turn + '</div></div>' +
