    },
    commands: {
      parse(text) {
        const t = String(text || '').trim();
        if (!t.startsWith('!')) return null;
        const parts = t.slice(1).trim().split(/\s+/).filter(Boolean);
        if (!parts.length) return null;
        return { command: parts[0].toLowerCase(), args: parts.slice(1), raw: t };
      },
      helpText() {
        return [
          'frontier_foundry_1.2 command set:',
          '!help - command list',
          '!status - state SITREP',
          '!ui - open operations iframe UI',
          '!hideui - close operations UI',
          '!travel <region-id> - execute travel turn',
          '!camp - execute camp turn',
          '!snapshot - save snapshot',
          '!restore <snapshot-id> - restore snapshot',
          '!new-expedition [seed] - start fresh deterministic world',
          '!reset - reset using current seed'
        ].join('\n');
      },
      handle(parsed) {
        const s = Engine.state;
        s.events.counters.command += 1;
        const c = parsed.command;
        if (c === 'help') {
          oc.thread.messages.push({ author: 'system', content: Systems.commands.helpText(), expectsReply: false });
          Systems.events.log('command', 'Displayed help output.');
        } else if (c === 'status') {
          const region = Engine.currentRegion();
          const txt = [
            'SITREP — frontier_foundry_1.2',
            'Seed: ' + s.expedition.seed,
            'Time: day ' + s.time.day + ', hour ' + s.time.hour + ', turn ' + s.time.turn,
            'Region: ' + (region ? region.name + ' [' + region.id + ']' : s.world.currentRegionId),
            'Weather: ' + s.world.weather.current + ' (sev ' + s.world.weather.severity + ', ' + s.world.weather.pressure + ')',
            'Resources: food ' + s.resources.stock.food + ', water ' + s.resources.stock.water + ', med ' + s.resources.stock.medicine + ', salvage ' + s.resources.stock.salvage + ', fuel ' + s.resources.stock.fuel,
            'Party avg morale/fatigue: ' + s.party.moraleAverage + '/' + s.party.fatigueAverage,
            'Active contracts: ' + s.contracts.active.length,
            'Scene: ' + s.scene.summary
          ].join('\n');
          oc.thread.messages.push({ author: 'system', content: txt, expectsReply: false });
          Systems.events.log('command', 'Displayed status output.');
        } else if (c === 'ui') {
          Systems.ui.open();
        } else if (c === 'hideui') {
          Systems.ui.close();
        } else if (c === 'travel') {
          Systems.actions.travel(parsed.args[0]);
          if (s.ui.visible) Systems.ui.render();
        } else if (c === 'camp') {
          Systems.actions.camp();
          if (s.ui.visible) Systems.ui.render();
        } else if (c === 'snapshot') {
          Systems.actions.saveSnapshot('command');
          if (s.ui.visible) Systems.ui.render();
        } else if (c === 'restore') {
          Systems.actions.restoreSnapshot(parsed.args[0]);
          if (s.ui.visible) Systems.ui.render();
        } else if (c === 'new-expedition') {
          Systems.actions.newExpedition(parsed.args[0]);
          if (s.ui.visible) Systems.ui.render();
        } else if (c === 'reset') {
          Systems.actions.resetCurrentSeed();
          if (s.ui.visible) Systems.ui.render();
        } else {
          oc.thread.messages.push({ author: 'system', content: 'Unknown command: ' + parsed.raw + '\nUse !help.', expectsReply: false });
        }

        Systems.context.syncReminder();
        Engine.writeState();
      }
    }
  };

  Engine.bootstrap();

  oc.thread.on('MessageAdded', ({ message }) => {
    if (!message || message.author !== 'user') return;

    const parsed = Systems.commands.parse(message.content);
    if (parsed) {
      const idx = oc.thread.messages.indexOf(message);
      if (idx >= 0) oc.thread.messages.splice(idx, 1);
      Systems.commands.handle(parsed);
      return;
    }

    Systems.context.injectHidden();
    Systems.context.syncReminder();
    Engine.writeState();
    if (Engine.state.ui.visible) Systems.ui.render();
  });
})();
